from typing import Protocol, TypedDict, runtime_checkable

class OrderTD(TypedDict):
    id: str
    total: float
    currency: str

@runtime_checkable  # BUG: runtime_checkable only works for Protocols with
class OrderPayload(Protocol):  # method members, not data attrs from TypedDict.
    id: str
    total: float
    currency: str

class Router:
    def dispatch(self, payload: dict):
        return self._handle_as(payload, OrderPayload)

    def _handle_as(self, payload, proto):
        if not isinstance(payload, proto):
            raise ValueError("payload does not satisfy protocol")
        return self._process(payload)

    def _process(self, payload):
        return payload["id"]

if __name__ == '__main__':
    r = Router()
    r.dispatch({"id": "abc", "total": 19.99, "currency": "USD"})
